  says: "#FFFFFF",
  action: "#C2A2DA",       // light purple for *actions
  radio: "#8FE6F5",         // light cyan/blue for radio chatter
  notice: "#FFB347",        // orange for [server] notices
  automated: "#A8D98F",     // soft green automated actions
  broadcast: "#F26C6C",     // red-ish for broadcast/ads/news/gov
