// ---------- Autosave ----------
// Settings (text, sliders, colors, font) are persisted via the artifact's
// window.storage API under the key "gtascreen-settings". See the load/save
// effects inside GTAScreenApp for implementation. Images are intentionally
// excluded from autosave (storage has a 5MB per-key limit).

// ---------- Toast system ----------
function useToasts() {
  const [toasts, setToasts] = useState([]);
  const push = useCallback((message, type = "info") => {
    const id = uid();
    setToasts((t) => [...t, { id, message, type }]);
    setTimeout(() => {
      setToasts((t) => t.filter((x) => x.id !== id));
    }, 3000);
  }, []);
  return { toasts, push };
}

function ToastStack({ toasts }) {
  return (
    <div className="fixed bottom-5 right-5 z-[100] flex flex-col gap-2 items-end pointer-events-none">
      {toasts.map((t) => (
        <div
          key={t.id}
          className={`pointer-events-auto flex items-center gap-2 px-4 py-3 rounded-xl shadow-2xl backdrop-blur-md border text-sm font-medium animate-toast-in
            ${t.type === "success" ? "bg-[#16241c]/95 border-emerald-500/30 text-emerald-300" :
              t.type === "error" ? "bg-[#241616]/95 border-red-500/30 text-red-300" :
              "bg-[#15171c]/95 border-[#2a2d35] text-[#d8dae0]"}`}
        >
          {t.type === "success" && <Check size={15} className="text-emerald-400" />}
          {t.type === "error" && <X size={15} className="text-red-400" />}
          {t.message}
        </div>
      ))}
    </div>
  );
}

