function DropZone({ label, hint, onFile, thumbnail, onClear, compact }) {
  const [dragOver, setDragOver] = useState(false);
  const inputRef = useRef(null);

  const handleFiles = (files) => {
    const file = files?.[0];
    if (file && file.type.startsWith("image/")) {
      onFile(file);
    }
  };

  const openPicker = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (inputRef.current) {
      inputRef.current.value = "";
      inputRef.current.click();
    }
  };

  return (
    <div
      onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
      onDragLeave={() => setDragOver(false)}
      onDrop={(e) => {
        e.preventDefault();
        setDragOver(false);
        handleFiles(e.dataTransfer.files);
      }}
      className={`relative rounded-xl border-2 border-dashed transition-all duration-150 overflow-hidden
        ${dragOver ? "border-[#3B6FE0] bg-[#3B6FE0]/10" : "border-[#262932] bg-[#0E0F13]"}
        ${compact ? "p-3" : "p-5"}`}
    >
      <input
        ref={inputRef}
        type="file"
        accept="image/*"
        style={{ position: "absolute", width: 1, height: 1, opacity: 0, pointerEvents: "none", top: 0, left: 0 }}
        onChange={(e) => { handleFiles(e.target.files); }}
      />
      {thumbnail ? (
        <div className="flex items-center gap-3">
          <img src={thumbnail} alt="" className="w-12 h-12 rounded-lg object-cover border border-[#21242C]" />
          <div className="flex-1 min-w-0">
            <p className="text-[12px] text-[#C7C9CF] font-medium truncate">{label} terpasang</p>
            <button onClick={openPicker} className="text-[11px] text-[#5C8BF2] underline-offset-2 hover:underline">Ketuk untuk mengganti</button>
          </div>
          <button
            onClick={(e) => { e.preventDefault(); e.stopPropagation(); onClear(); }}
            className="relative z-10 p-1.5 rounded-lg hover:bg-[#1c1f26] text-[#6b6f78] hover:text-red-400 transition-colors"
          >
            <Trash2 size={14} />
          </button>
        </div>
      ) : (
        <button
          type="button"
          onClick={openPicker}
          className="w-full flex flex-col items-center justify-center text-center py-2 gap-2"
        >
          <div className="w-9 h-9 rounded-full bg-[#1a1c22] flex items-center justify-center">
            <Upload size={16} className="text-[#5C8BF2]" />
          </div>
          <span className="text-[12.5px] font-medium text-[#C7C9CF]">{label}</span>
          <span className="text-[11px] text-[#5b5e66] leading-snug max-w-[200px]">{hint}</span>
          <span className="mt-1 text-[11.5px] font-semibold text-white bg-[#3B6FE0] px-4 py-1.5 rounded-lg">
            Pilih File
          </span>
        </button>
      )}
    </div>
  );
}

// ---------- Chat parsing ----------
// Determines styling category for a line based on simple keyword heuristics
function classifyLine(line, characterName) {
  const trimmed = line.trim();
  if (!trimmed) return null;

  const lower = trimmed.toLowerCase();

  if (trimmed.startsWith("*")) {
    return { category: "action", text: trimmed };
  }
  if (lower.includes("[radio]") || lower.includes("(radio)") || lower.includes("says [radio]") || lower.startsWith("(") && lower.includes("radio")) {
    return { category: "radio", text: trimmed };
  }
  if (lower.startsWith("server:") || lower.startsWith("notice:") || lower.startsWith("[server]") || lower.includes("automatic")) {
    if (lower.includes("auto")) return { category: "automated", text: trimmed };
    return { category: "notice", text: trimmed };
  }
  if (lower.startsWith("ad:") || lower.startsWith("news:") || lower.startsWith("broadcast")) {
    return { category: "broadcast", text: trimmed };
  }
  if (lower.startsWith("gov:") || lower.includes("government")) {
    return { category: "government", text: trimmed };
  }
  if (lower.startsWith("faction:") || lower.includes("(faction)")) {
    return { category: "faction", text: trimmed };
  }
  if (lower.includes("(low)") || lower.includes("/low")) {
    return { category: "says", text: trimmed, isLow: true };
  }
  return { category: "says", text: trimmed };
}

function parseChatLog(raw, filters, characterName) {
  if (!raw) return [];
  const lines = raw.split("\n");
  const result = [];
  for (const line of lines) {
    const parsed = classifyLine(line, characterName);
    if (!parsed) continue;

    // apply filters
    if (parsed.category === "notice" && !filters.notices) continue;
    if (parsed.category === "radio" && !filters.radio) continue;
    if (parsed.category === "automated" && !filters.automated) continue;
    if (parsed.category === "broadcast" && !filters.broadcasts) continue;
    if (parsed.category === "government" && !filters.government) continue;
    if (parsed.category === "faction" && !filters.faction) continue;

    result.push(parsed);
  }
  return result;
}

// ---------- Canvas rendering ----------

function wrapText(ctx, text, maxWidth) {
  const words = text.split(" ");
  const lines = [];
  let current = "";
  for (const word of words) {
    const test = current ? current + " " + word : word;
    if (ctx.measureText(test).width > maxWidth && current) {
      lines.push(current);
      current = word;
    } else {
      current = test;
    }
  }
  if (current) lines.push(current);
  return lines;
}

function drawChatBlock({ ctx, lines, x, yStart, fromBottom, canvasW, canvasH, settings, characterName }) {
  const {
    font, fontSize, stroke, letterSpacing, lineHeight, posXPct, posYPct,
    textColor, strokeColor, shadowColor, shadowBlur, shadowOpacity, useBackground, bgColor, useMask
  } = settings;

  const fontObj = FONT_OPTIONS.find((f) => f.value === font) || FONT_OPTIONS[0];
  ctx.font = `${fontObj.weight} ${fontSize}px ${font}`;
  ctx.textBaseline = "alphabetic";

  const maxWidth = canvasW * 0.62;
  const measured = [];

  lines.forEach((item) => {
    const wrapped = wrapText(ctx, item.text, maxWidth);
    wrapped.forEach((w, i) => measured.push({ text: w, category: item.category, isLow: item.isLow, firstOfGroup: i === 0 }));
  });

  const lh = fontSize * (lineHeight / 100) * 1.0;
  const baseX = canvasW * (posXPct / 100);
  const baseY = fromBottom
    ? canvasH - canvasH * (posYPct / 100)
    : canvasH * (posYPct / 100);

  let drawList = measured;
  let startY;
  if (fromBottom) {
    startY = baseY - (drawList.length - 1) * lh;
  } else {
    startY = baseY;
  }

  // background panel: one tight box per line (not one big box for the whole block)
  if (useBackground) {
    const padX = 8, padY = 4;
    drawList.forEach((l, idx) => {
      const y = startY + idx * lh;
      const w = ctx.measureText(l.text).width;
      const boxH = fontSize + padY * 2;
      ctx.save();
      ctx.fillStyle = bgColor;
      ctx.globalAlpha = useMask ? 0.55 : 0.85;
      ctx.fillRect(baseX - padX, y - fontSize - padY + 3, w + padX * 2, boxH);
      ctx.restore();
    });
  }

  drawList.forEach((l, idx) => {
    const y = startY + idx * lh;
    const color = colorForCategory(l.category, l.isLow, textColor);

    const isArialBlack = font.includes("Arial Black");

    ctx.save();
    if (shadowBlur > 0) {
      ctx.shadowColor = hexToRgba(shadowColor, shadowOpacity / 100);
      ctx.shadowBlur = shadowBlur;
      ctx.shadowOffsetX = 1;
      ctx.shadowOffsetY = 1;
    }

    if (isArialBlack) {
      // pixelated/jagged rendering for GTA SA look
      drawPixelatedText(ctx, l.text, baseX, y, color, strokeColor, stroke, fontSize, font, fontObj.weight);
    } else if (letterSpacing && letterSpacing !== 0) {
      drawSpacedText(ctx, l.text, baseX, y, letterSpacing, stroke, strokeColor, color);
    } else {
      if (stroke > 0) {
        ctx.lineJoin = "round";
        ctx.miterLimit = 2;
        ctx.lineWidth = stroke * 2;
        ctx.strokeStyle = strokeColor;
        ctx.strokeText(l.text, baseX, y);
      }
      ctx.fillStyle = color;
      ctx.fillText(l.text, baseX, y);
    }
    ctx.restore();
  });

  return drawList.length * lh;
}

function drawSpacedText(ctx, text, x, y, spacing, stroke, strokeColor, fillColor) {
  let cursor = x;
  for (const ch of text) {
    if (stroke > 0) {
      ctx.lineJoin = "round";
      ctx.lineWidth = stroke * 2;
      ctx.strokeStyle = strokeColor;
      ctx.strokeText(ch, cursor, y);
    }
    ctx.fillStyle = fillColor;
    ctx.fillText(ch, cursor, y);
    cursor += ctx.measureText(ch).width + spacing;
  }
}

// Jagged/pixelated text stamp — renders text to a small offscreen canvas
// then stamps it back without smoothing, producing GTA SA–style stepped edges.
function drawPixelatedText(ctx, text, x, y, fillColor, strokeColor, strokeW, fontSize, font, fontWeight) {
  // GTA SA look comes from font weight + stroke, not pixel artifacts.
  // Render normally — clean and readable.
  if (strokeW > 0) {
    ctx.lineJoin = "round";
    ctx.miterLimit = 2;
    ctx.lineWidth = strokeW * 2;
    ctx.strokeStyle = strokeColor;
    ctx.strokeText(text, x, y);
  }
  ctx.fillStyle = fillColor;
  ctx.fillText(text, x, y);
}

function colorForCategory(category, isLow, customTextColor) {
  if (isLow) return "#FFFFFF";
  switch (category) {
    case "action": return SAMP_COLORS.action;
    case "radio": return SAMP_COLORS.radio;
    case "notice": return SAMP_COLORS.notice;
    case "automated": return SAMP_COLORS.automated;
    case "broadcast": return SAMP_COLORS.broadcast;
    case "government": return SAMP_COLORS.government;
    case "faction": return SAMP_COLORS.faction;
    case "says":
    default:
      return customTextColor || SAMP_COLORS.says;
  }
}

function roundRect(ctx, x, y, w, h, r) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.arcTo(x + w, y, x + w, y + h, r);
  ctx.arcTo(x + w, y + h, x, y + h, r);
  ctx.arcTo(x, y + h, x, y, r);
  ctx.arcTo(x, y, x + w, y, r);
  ctx.closePath();
}

function hexToRgba(hex, alpha) {
  const h = hex.replace("#", "");
  const bigint = parseInt(h.length === 3 ? h.split("").map((c) => c + c).join("") : h, 16);
  const r = (bigint >> 16) & 255, g = (bigint >> 8) & 255, b = bigint & 255;
  return `rgba(${r},${g},${b},${alpha})`;
}

// ---------- Main App ----------

export default function GTAScreenApp() {
  const { toasts, push } = useToasts();

  // images
  const [background, setBackground] = useState(null); // dataURL
  const [bgImageObj, setBgImageObj] = useState(null);
  const [objectImg, setObjectImg] = useState(null);
  const [objectImgObj, setObjectImgObj] = useState(null);
  const [objSize, setObjSize] = useState(50);
  const [objPosX, setObjPosX] = useState(50);
  const [objPosY, setObjPosY] = useState(50);

  // chat content
  const [topChat, setTopChat] = useState(DEFAULT_TOP_CHATLOG);
  const [bottomChat, setBottomChat] = useState(DEFAULT_BOTTOM_CHATLOG);

  // theme
  const [theme, setTheme] = useState("dark"); // "dark" | "light"

  // export quality
  const [quality, setQuality] = useState(3);

  const [topOpts, setTopOpts] = useState({ useBackground: false, useMask: false, outside: false });
  const [bottomOpts, setBottomOpts] = useState({ useBackground: false, useMask: false, outside: false });
  const [chatBgColor, setChatBgColor] = useState("#000000");

  // filters
  const [filters, setFilters] = useState({
    notices: true, radio: true, automated: false, broadcasts: false, government: false, faction: false,
  });

  // resolution
  const [resW, setResW] = useState(1280);
  const [resH, setResH] = useState(720);

  // offsets
  const [leftOffset, setLeftOffset] = useState(30);
  const [topOffset, setTopOffset] = useState(10);

  // font
  const [font, setFont] = useState(FONT_OPTIONS[0].value);
  const [fontSize, setFontSize] = useState(14);
  const [stroke, setStroke] = useState(2);
  const [shadowBlur, setShadowBlur] = useState(3);
  const [shadowOpacity, setShadowOpacity] = useState(70);
  const [letterSpacing, setLetterSpacing] = useState(0);
  const [lineHeight, setLineHeight] = useState(135);

  // text position (percentage based, independent per chat block)
  const [topPosX, setTopPosX] = useState(2);
  const [bottomPosX, setBottomPosX] = useState(2);
  const [topPosY, setTopPosY] = useState(5);
  const [bottomPosY, setBottomPosY] = useState(5);

  // colors
  const [textColor, setTextColor] = useState("#FFFFFF");
  const [strokeColor, setStrokeColor] = useState("#000000");
  const [shadowColor, setShadowColor] = useState("#000000");

  const [characterName, setCharacterName] = useState("");
  const [fileName, setFileName] = useState("");

  // zoom
  const [zoom, setZoom] = useState(1);
  const [fitMode, setFitMode] = useState(true);

  // autosave
  const [settingsLoaded, setSettingsLoaded] = useState(false);
  const saveTimeoutRef = useRef(null);

  const canvasRef = useRef(null);
  const wrapperRef = useRef(null);
  const fileObjInputRef = useRef(null);

  // ----- image loaders -----
  const handleBgFile = (file) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      setBackground(e.target.result);
      const img = new Image();
      img.onload = () => setBgImageObj(img);
      img.src = e.target.result;
      push("Background berhasil diunggah", "success");
    };
    reader.readAsDataURL(file);
  };

  const handleObjFile = (file) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      setObjectImg(e.target.result);
      const img = new Image();
      img.onload = () => setObjectImgObj(img);
      img.src = e.target.result;
      push("Objek berhasil diunggah", "success");
    };
    reader.readAsDataURL(file);
  };

  // ----- rendering -----
  const drawToCanvas = useCallback((canvas, opts = {}) => {
    if (!canvas) return;
    const { forExport = false, jpgBackground = false } = opts;
    canvas.width = resW;
    canvas.height = resH;
    const ctx = canvas.getContext("2d", { alpha: true });
    ctx.clearRect(0, 0, resW, resH);

    // background
    if (bgImageObj) {
      const scale = Math.max(resW / bgImageObj.width, resH / bgImageObj.height);
      const dw = bgImageObj.width * scale;
      const dh = bgImageObj.height * scale;
      ctx.drawImage(bgImageObj, (resW - dw) / 2, (resH - dh) / 2, dw, dh);
    } else if (jpgBackground) {
      // JPG has no alpha channel: fill solid dark instead of white
      ctx.fillStyle = "#1A1A1A";
      ctx.fillRect(0, 0, resW, resH);
    } else if (!forExport) {
      // no background, preview only: keep canvas transparent, show a subtle placeholder hint
      ctx.save();
      ctx.fillStyle = "rgba(255,255,255,0.18)";
      ctx.font = "bold 28px Inter, sans-serif";
      ctx.textAlign = "center";
      ctx.fillText("TIDAK ADA FOTO BACKGROUND", resW / 2, resH / 2);
      ctx.textAlign = "left";
      ctx.restore();
    }
    // else: no background, exporting to PNG/clipboard -> stays fully transparent, no placeholder text

    // optional object overlay
    if (objectImgObj) {
      const targetW = resW * (objSize / 100);
      const ratio = objectImgObj.height / objectImgObj.width;
      const targetH = targetW * ratio;
      const ox = resW * (objPosX / 100) - targetW / 2;
      const oy = resH * (objPosY / 100) - targetH / 2;
      ctx.drawImage(objectImgObj, ox, oy, targetW, targetH);
    }

    const baseSettings = {
      font, fontSize, stroke, letterSpacing, lineHeight,
      textColor, strokeColor, shadowColor, shadowBlur, shadowOpacity,
      bgColor: chatBgColor,
    };

    const topLines = parseChatLog(topChat, filters, characterName);
    const bottomLines = parseChatLog(bottomChat, filters, characterName);

    if (topLines.length) {
      drawChatBlock({
        ctx, lines: topLines,
        x: leftOffset, yStart: topOffset, fromBottom: false,
        canvasW: resW, canvasH: resH,
        settings: { ...baseSettings, posXPct: topPosX, posYPct: topPosY, useBackground: topOpts.useBackground, useMask: topOpts.useMask },
        characterName,
      });
    }
    if (bottomLines.length) {
      drawChatBlock({
        ctx, lines: bottomLines,
        x: leftOffset, yStart: topOffset, fromBottom: true,
        canvasW: resW, canvasH: resH,
        settings: { ...baseSettings, posXPct: bottomPosX, posYPct: bottomPosY, useBackground: bottomOpts.useBackground, useMask: bottomOpts.useMask },
        characterName,
      });
    }
  }, [
    resW, resH, bgImageObj, objectImgObj, objSize, objPosX, objPosY,
    topChat, bottomChat, filters, font, fontSize, stroke, letterSpacing, lineHeight,
    textColor, strokeColor, shadowColor, shadowBlur, shadowOpacity, chatBgColor,
    leftOffset, topOffset, topPosX, bottomPosX, topPosY, bottomPosY, topOpts, bottomOpts, characterName,
  ]);

  const miniCanvasRef = useRef(null);

  // ----- autosave: load settings on mount -----
  useEffect(() => {
    (async () => {
      try {
        const result = await window.storage.get("gtascreen-settings", false);
        if (result && result.value) {
          const s = JSON.parse(result.value);
          if (s.topChat !== undefined) setTopChat(s.topChat);
          if (s.bottomChat !== undefined) setBottomChat(s.bottomChat);
          if (s.topOpts) setTopOpts(s.topOpts);
          if (s.bottomOpts) setBottomOpts(s.bottomOpts);
          if (s.chatBgColor) setChatBgColor(s.chatBgColor);
          if (s.filters) setFilters(s.filters);
          if (s.resW) setResW(s.resW);
          if (s.resH) setResH(s.resH);
          if (s.leftOffset !== undefined) setLeftOffset(s.leftOffset);
          if (s.topOffset !== undefined) setTopOffset(s.topOffset);
          if (s.font) setFont(s.font);
          if (s.fontSize) setFontSize(s.fontSize);
          if (s.stroke !== undefined) setStroke(s.stroke);
          if (s.shadowBlur !== undefined) setShadowBlur(s.shadowBlur);
          if (s.shadowOpacity !== undefined) setShadowOpacity(s.shadowOpacity);
          if (s.letterSpacing !== undefined) setLetterSpacing(s.letterSpacing);
          if (s.lineHeight) setLineHeight(s.lineHeight);
          if (s.posX !== undefined) { setTopPosX(s.posX); setBottomPosX(s.posX); }
          if (s.topPosX !== undefined) setTopPosX(s.topPosX);
          if (s.bottomPosX !== undefined) setBottomPosX(s.bottomPosX);
          if (s.topPosY !== undefined) setTopPosY(s.topPosY);
          if (s.bottomPosY !== undefined) setBottomPosY(s.bottomPosY);
          if (s.theme) setTheme(s.theme);
          if (s.quality) setQuality(s.quality);
          if (s.textColor) setTextColor(s.textColor);
          if (s.strokeColor) setStrokeColor(s.strokeColor);
          if (s.shadowColor) setShadowColor(s.shadowColor);
          if (s.characterName !== undefined) setCharacterName(s.characterName);
          if (s.fileName !== undefined) setFileName(s.fileName);
          push("Pengaturan tersimpan berhasil dimuat", "success");
        }
      } catch (err) {
        // no saved settings yet, or storage unavailable — start fresh silently
      } finally {
        setSettingsLoaded(true);
      }
    })();
  }, []);

  // ----- autosave: persist settings on change (debounced) -----
  useEffect(() => {
    if (!settingsLoaded) return; // don't overwrite saved settings before initial load completes
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    saveTimeoutRef.current = setTimeout(async () => {
      const snapshot = {
        topChat, bottomChat, topOpts, bottomOpts, chatBgColor, filters,
        resW, resH, leftOffset, topOffset, font, fontSize, stroke,
        shadowBlur, shadowOpacity, letterSpacing, lineHeight,
        topPosX, bottomPosX, topPosY, bottomPosY, textColor, strokeColor, shadowColor,
        characterName, fileName, theme, quality,
      };
      try {
        await window.storage.set("gtascreen-settings", JSON.stringify(snapshot), false);
      } catch (err) {
        // saving failed silently; non-critical for app function
      }
    }, 800);
    return () => clearTimeout(saveTimeoutRef.current);
  }, [
    settingsLoaded, topChat, bottomChat, topOpts, bottomOpts, chatBgColor, filters,
    resW, resH, leftOffset, topOffset, font, fontSize, stroke,
    shadowBlur, shadowOpacity, letterSpacing, lineHeight,
    topPosX, bottomPosX, topPosY, bottomPosY, textColor, strokeColor, shadowColor,
    characterName, fileName, theme, quality,
  ]);

  const render = useCallback(() => {
    drawToCanvas(canvasRef.current);
    drawToCanvas(miniCanvasRef.current);
  }, [drawToCanvas]);

  useEffect(() => { render(); }, [render]);

  // re-render once custom fonts (e.g. Tommy Soft from base64) finish loading,
  // since canvas text can be drawn before the font is ready otherwise
  useEffect(() => {
    if (document.fonts && document.fonts.ready) {
      document.fonts.ready.then(() => render());
    }
  }, [render]);

  // ----- zoom / fit -----
  const [containerSize, setContainerSize] = useState({ w: 600, h: 400 });
  useEffect(() => {
    const el = wrapperRef.current;
    if (!el) return;
    const obs = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setContainerSize({ w: entry.contentRect.width, h: entry.contentRect.height });
      }
    });
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  const fitScale = useMemo(() => {
    const padding = 48;
    const sw = (containerSize.w - padding) / resW;
    const sh = (containerSize.h - padding) / resH;
    return Math.max(Math.min(sw, sh, 1.5), 0.05);
  }, [containerSize, resW, resH]);

  const effectiveZoom = fitMode ? fitScale : zoom;

  // ----- export -----
  const qualityCfg = QUALITY_LEVELS.find((q) => q.value === quality) || QUALITY_LEVELS[2];

  const renderQualityCanvas = (opts = {}) => {
    // render at a reduced internal scale (for low quality) then upscale to nominal
    // resolution, so both background image AND text inherit a soft, compressed look.
    const scale = qualityCfg.scale;
    if (scale >= 1) {
      const c = document.createElement("canvas");
      drawToCanvas(c, opts);
      return c;
    }
    const small = document.createElement("canvas");
    const savedW = resW, savedH = resH;
    small.width = Math.max(1, Math.round(savedW * scale));
    small.height = Math.max(1, Math.round(savedH * scale));
    // draw scaled-down by temporarily drawing to a canvas sized at full res, then
    // downscale using drawImage onto the small canvas (keeps text proportions correct)
    const full = document.createElement("canvas");
    drawToCanvas(full, opts);
    const sctx = small.getContext("2d", { alpha: true });
    sctx.imageSmoothingEnabled = true;
    sctx.drawImage(full, 0, 0, small.width, small.height);
    const upscaled = document.createElement("canvas");
    upscaled.width = savedW;
    upscaled.height = savedH;
    const uctx = upscaled.getContext("2d", { alpha: true });
    uctx.imageSmoothingEnabled = true;
    uctx.drawImage(small, 0, 0, savedW, savedH);
    return upscaled;
  };

  const exportImage = async (format) => {
    const mime = format === "jpg" ? "image/jpeg" : "image/png";
    const ext = format === "jpg" ? "jpg" : "png";
    const exportCanvas = renderQualityCanvas({ forExport: true, jpgBackground: format === "jpg" });

    if (format === "png") {
      // toDataURL preserves alpha channel more reliably across browsers
      const dataUrl = exportCanvas.toDataURL("image/png");
      const a = document.createElement("a");
      a.href = dataUrl;
      a.download = `${fileName || "GTAScreen-export"}.png`;
      document.body.appendChild(a);
      a.click();
      a.remove();
      push("Berhasil diunduh sebagai PNG", "success");
    } else {
      exportCanvas.toBlob((blob) => {
        if (!blob) return;
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `${fileName || "GTAScreen-export"}.jpg`;
        document.body.appendChild(a);
        a.click();
        a.remove();
        URL.revokeObjectURL(url);
        push("Berhasil diunduh sebagai JPG", "success");
      }, mime, qualityCfg.jpegQuality);
    }
  };

  const copyToClipboard = async () => {
    try {
      const exportCanvas = renderQualityCanvas({ forExport: true });
      exportCanvas.toBlob(async (blob) => {
        if (!blob) return;
        await navigator.clipboard.write([new ClipboardItem({ "image/png": blob })]);
        push("Gambar disalin ke clipboard", "success");
      }, "image/png", qualityCfg.jpegQuality);
    } catch (err) {
      push("Gagal menyalin ke clipboard", "error");
    }
  };

  const resetZoom = () => { setFitMode(true); setZoom(1); };

  const isLight = theme === "light";

  return (
    <div
      className="min-h-screen w-full flex flex-col transition-colors duration-200"
      style={{
        fontFamily: "Inter, sans-serif",
        background: isLight ? "#F5F6F8" : "#0A0B0D",
        color: isLight ? "#1A1C22" : "#E8E9EB",
        "--card-bg": isLight ? "#FFFFFF" : "#13151A",
        "--card-border": isLight ? "#E2E4E9" : "#21242C",
        "--input-bg": isLight ? "#FFFFFF" : "#0E0F13",
        "--input-border": isLight ? "#D8DAE0" : "#21242C",
        "--input-text": isLight ? "#1A1C22" : "#E8E9EB",
        "--input-placeholder": isLight ? "#9A9DA6" : "#4a4d55",
      }}
    >
      <FontLoader />
      <GlobalStyles />

      {/* Top bar */}
      <header
        className="h-16 shrink-0 flex items-center justify-between px-5 lg:px-7 backdrop-blur sticky top-0 z-30"
        style={{
          borderBottom: `1px solid ${isLight ? "#E2E4E9" : "#1A1C22"}`,
          background: isLight ? "rgba(245,246,248,0.95)" : "rgba(10,11,13,0.95)",
        }}
      >
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-[#3B6FE0] to-[#23448f] flex items-center justify-center shadow-lg shadow-[#3B6FE0]/20">
            <span className="text-white font-black text-sm" style={{ fontFamily: "Anton, sans-serif" }}>G</span>
          </div>
          <div>
            <h1 className="text-[17px] font-bold leading-none tracking-tight" style={{ fontFamily: "Anton, sans-serif", letterSpacing: "0.5px" }}>
              GTA<span className="text-[#5C8BF2]">Screen</span>
            </h1>
            <p className="text-[10.5px] text-[#5b5e66] mt-0.5 leading-none hidden sm:block">Create Professional GTA Roleplay Screenshots.</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button
            onClick={() => setTheme(isLight ? "dark" : "light")}
            className="text-[10.5px] font-medium px-2.5 py-1 rounded-full border transition-colors"
            style={{ borderColor: isLight ? "#D8DAE0" : "#21242C", color: isLight ? "#1A1C22" : "#E8E9EB" }}
            title="Ganti tema terang/gelap"
          >
            {isLight ? "🌙 Gelap" : "☀️ Terang"}
          </button>
          <span className="text-[11px] text-[#5b5e66] hidden md:inline px-2.5 py-1 rounded-full border border-[#21242C]">SA-MP Style Renderer</span>
          <span className="text-[10.5px] text-[#5b5e66] flex items-center gap-1.5 px-2.5 py-1 rounded-full border border-[#21242C]" title="Pengaturan teks, slider, warna & font tersimpan otomatis (gambar tidak ikut tersimpan)">
            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500" />
            Autosave aktif
          </span>
          <button
            onClick={async () => {
              try {
                await window.storage.delete("gtascreen-settings", false);
                push("Pengaturan tersimpan dihapus. Refresh untuk mulai baru.", "success");
              } catch (err) {
                push("Tidak ada pengaturan tersimpan untuk dihapus", "info");
              }
            }}
            className="text-[10.5px] text-[#5b5e66] hover:text-red-400 px-2.5 py-1 rounded-full border border-[#21242C] hover:border-red-500/30 transition-colors"
            title="Hapus pengaturan tersimpan"
          >
            Reset
          </button>
        </div>
      </header>

      <div className="flex flex-1 flex-col lg:flex-row overflow-hidden">
        {/* SIDEBAR */}
        <aside
          className="w-full lg:w-[380px] xl:w-[420px] shrink-0 overflow-y-auto px-4 py-4 lg:max-h-[calc(100vh-64px)] gts-scroll border-b lg:border-b-0 lg:border-r"
          style={{ borderColor: isLight ? "#E2E4E9" : "#1A1C22" }}
        >

          <Collapsible title="Background" icon={ImageIcon} defaultOpen={true}>
            <DropZone
              label="Background"
              hint="Tarik & lepas gambar di sini, atau klik untuk memilih file. Format apa pun yang didukung browser."
              onFile={handleBgFile}
              thumbnail={background}
              onClear={() => { setBackground(null); setBgImageObj(null); }}
            />
          </Collapsible>

          <Collapsible title="Objek (Opsional)" icon={Move} defaultOpen={false}>
            <DropZone
              label="Objek PNG"
              hint="Tambahkan gambar PNG transparan yang dapat dipindahkan & diubah ukurannya."
              onFile={handleObjFile}
              thumbnail={objectImg}
              onClear={() => { setObjectImg(null); setObjectImgObj(null); }}
              compact
            />
            {objectImg && (
              <div className="mt-3">
                <SliderRow label="Ukuran" value={objSize} min={5} max={100} unit="%" onChange={setObjSize} />
                <SliderRow label="Posisi X" value={objPosX} min={0} max={100} unit="%" onChange={setObjPosX} />
                <SliderRow label="Posisi Y" value={objPosY} min={0} max={100} unit="%" onChange={setObjPosY} />
                <button
                  onClick={() => { setObjectImg(null); setObjectImgObj(null); push("Objek dihapus"); }}
                  className="w-full mt-1 flex items-center justify-center gap-1.5 text-[12px] font-medium text-red-400 hover:bg-red-500/10 rounded-lg py-2 transition-colors"
                >
                  <Trash2 size={13} /> Hapus Objek
                </button>
              </div>
            )}
          </Collapsible>

          <Collapsible title="Chat Atas" icon={MessageSquare} defaultOpen={true}>
            <textarea
              value={topChat}
              onChange={(e) => setTopChat(e.target.value)}
              placeholder={`Jordan Baker lights a cigarette.\nJordan Baker says: What's good homie?\nNathan Harper says: We chillin'.`}
              rows={5}
              className="gts-input w-full rounded-lg px-3 py-2.5 text-[12.5px] leading-relaxed outline-none focus:border-[#3B6FE0] transition-colors resize-none font-mono"
            />
            <div className="mt-2.5">
              <Checkbox checked={topOpts.useBackground} onChange={(v) => setTopOpts((p) => ({ ...p, useBackground: v }))} label="Gunakan Background Chat" />
              <Checkbox checked={topOpts.useMask} onChange={(v) => setTopOpts((p) => ({ ...p, useMask: v }))} label="Gunakan Mask Background" />
              <Checkbox checked={topOpts.outside} onChange={(v) => setTopOpts((p) => ({ ...p, outside: v }))} label="Tampilkan di Luar Gambar" />
            </div>
          </Collapsible>

          <Collapsible title="Chat Bawah" icon={MessageSquare} defaultOpen={true}>
            <textarea
              value={bottomChat}
              onChange={(e) => setBottomChat(e.target.value)}
              rows={6}
              className="gts-input w-full rounded-lg px-3 py-2.5 text-[12.5px] leading-relaxed outline-none focus:border-[#3B6FE0] transition-colors resize-none font-mono"
            />
            <div className="mt-2.5">
              <Checkbox checked={bottomOpts.useBackground} onChange={(v) => setBottomOpts((p) => ({ ...p, useBackground: v }))} label="Gunakan Background Chat" />
              <Checkbox checked={bottomOpts.useMask} onChange={(v) => setBottomOpts((p) => ({ ...p, useMask: v }))} label="Gunakan Mask Background" />
              <Checkbox checked={bottomOpts.outside} onChange={(v) => setBottomOpts((p) => ({ ...p, outside: v }))} label="Tampilkan di Luar Gambar" />
            </div>
            {(topOpts.useBackground || bottomOpts.useBackground) && (
              <div className="mt-3 pt-3 border-t border-[#1A1C22]">
                <ColorField label="Warna Background Chat" value={chatBgColor} onChange={setChatBgColor} />
              </div>
            )}
          </Collapsible>

          <Collapsible title="Filtering" icon={Sliders} defaultOpen={true}>
            <Checkbox checked={filters.notices} onChange={(v) => setFilters((p) => ({ ...p, notices: v }))} label="Include Notices" color={SAMP_COLORS.notice} />
            <Checkbox checked={filters.radio} onChange={(v) => setFilters((p) => ({ ...p, radio: v }))} label="Include Radio" color={SAMP_COLORS.radio} />
            <Checkbox checked={filters.automated} onChange={(v) => setFilters((p) => ({ ...p, automated: v }))} label="Include Automated Actions" color={SAMP_COLORS.automated} />
            <Checkbox checked={filters.broadcasts} onChange={(v) => setFilters((p) => ({ ...p, broadcasts: v }))} label="Include Broadcasts (Ads, News, Government)" color={SAMP_COLORS.broadcast} />
            <Checkbox checked={filters.government} onChange={(v) => setFilters((p) => ({ ...p, government: v }))} label="Include Government Messages" color={SAMP_COLORS.government} />
            <Checkbox checked={filters.faction} onChange={(v) => setFilters((p) => ({ ...p, faction: v }))} label="Include Faction Messages" color={SAMP_COLORS.faction} />
          </Collapsible>

          <Collapsible title="Pengaturan Screenshot" icon={Settings2} defaultOpen={true}>
            <p className="text-[11px] text-[#5b5e66] mb-2.5 -mt-1">Resolusi hasil gambar. Default 800 × 600.</p>
            <div className="flex gap-2 mb-3">
              <div className="flex-1">
                <label className="text-[11px] text-[#5b5e66] block mb-1">Width</label>
                <TextInput value={String(resW)} onChange={(v) => setResW(parseInt(v) || 0)} />
              </div>
              <div className="flex-1">
                <label className="text-[11px] text-[#5b5e66] block mb-1">Height</label>
                <TextInput value={String(resH)} onChange={(v) => setResH(parseInt(v) || 0)} />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-2">
              {RESOLUTION_PRESETS.map((p) => (
                <button
                  key={p.label}
                  onClick={() => { setResW(p.w); setResH(p.h); }}
                  className={`text-[11.5px] font-medium py-2 rounded-lg border transition-colors
                    ${resW === p.w && resH === p.h ? "bg-[#3B6FE0]/15 border-[#3B6FE0] text-[#7da3ef]" : "bg-[#0E0F13] border-[#21242C] text-[#9AA0AC] hover:border-[#363b46]"}`}
                >
                  {p.label}
                </button>
              ))}
            </div>

            <div className="mt-4 pt-3 border-t border-[#1A1C22]">
              <label className="text-[11px] text-[#5b5e66] block mb-1.5">Quality (saat menyimpan gambar)</label>
              <Dropdown
                value={String(quality)}
                onChange={(v) => setQuality(parseInt(v))}
                options={QUALITY_LEVELS.map((q) => ({ value: String(q.value), label: q.label }))}
              />
              <p className="text-[10.5px] text-[#5b5e66] mt-1.5 leading-snug">Quality lebih rendah akan membuat hasil gambar (termasuk teks) sedikit buram, seperti hasil screenshot kompresi rendah.</p>
            </div>
          </Collapsible>

          {/* Mini preview — muncul di tengah sidebar khusus mobile, biar gak perlu scroll jauh */}
          <div className="lg:hidden mb-3">
            <Card>
              <SectionLabel icon={ImageIcon}>Preview</SectionLabel>
              <div className="w-full rounded-lg overflow-hidden bg-[#070809] flex items-center justify-center p-2 gts-canvas-bg">
                <canvas
                  ref={miniCanvasRef}
                  style={{ width: "100%", height: "auto", display: "block", maxHeight: 220, objectFit: "contain" }}
                />
              </div>
              <p className="text-[10.5px] text-[#5b5e66] mt-2 text-center">Preview langsung update saat kamu ubah pengaturan di bawah.</p>
            </Card>
          </div>

          <Collapsible title="Offset Teks" icon={Move} defaultOpen={false}
            >
            <p className="text-[11px] text-[#5b5e66] mb-1 -mt-1">Seberapa jauh teks dari tepi gambar. Default 30 × 10 (gaya SA-MP).</p>
            <SliderRow label="Left Offset" value={leftOffset} min={0} max={200} unit="px" onChange={setLeftOffset} />
            <SliderRow label="Top Offset" value={topOffset} min={0} max={200} unit="px" onChange={setTopOffset} />
          </Collapsible>

          <Collapsible title="Font" icon={Type} defaultOpen={true}>
            <Dropdown value={font} onChange={setFont} options={FONT_OPTIONS} />
          </Collapsible>

          <Collapsible title="Pengaturan Font" icon={Sliders} defaultOpen={false}>
            <SliderRow label="Ukuran" value={fontSize} min={8} max={48} unit="px" onChange={setFontSize} />
            <SliderRow label="Stroke" value={stroke} min={0} max={6} unit="px" onChange={setStroke} />
            <SliderRow label="Shadow Blur" value={shadowBlur} min={0} max={20} unit="px" onChange={setShadowBlur} />
            <SliderRow label="Shadow Opacity" value={shadowOpacity} min={0} max={100} unit="%" onChange={setShadowOpacity} />
            <SliderRow label="Letter Spacing" value={letterSpacing} min={-2} max={10} unit="px" onChange={setLetterSpacing} />
            <SliderRow label="Line Height" value={lineHeight} min={80} max={250} unit="%" onChange={setLineHeight} />
          </Collapsible>

          <Collapsible title="Posisi Teks" icon={Move} defaultOpen={false}>
            <div className="pt-1">
              <p className="text-[11px] font-semibold text-[#5C8BF2] mb-2">Chat Atas</p>
              <SliderRow label="Posisi X" value={topPosX} min={0} max={100} unit="%" onChange={setTopPosX} />
              <SliderRow label="Posisi Y" value={topPosY} min={0} max={100} unit="%" onChange={setTopPosY} />
            </div>
            <div className="mt-1 pt-3 border-t border-[#1A1C22]">
              <p className="text-[11px] font-semibold text-[#5C8BF2] mb-2">Chat Bawah</p>
              <SliderRow label="Posisi X" value={bottomPosX} min={0} max={100} unit="%" onChange={setBottomPosX} />
              <SliderRow label="Posisi Y (dari bawah)" value={bottomPosY} min={0} max={100} unit="%" onChange={setBottomPosY} />
            </div>
          </Collapsible>

          <Collapsible title="Warna" icon={Palette} defaultOpen={false}>
            <ColorField label="Warna Teks" value={textColor} onChange={setTextColor} />
            <ColorField label="Warna Stroke" value={strokeColor} onChange={setStrokeColor} />
            <ColorField label="Warna Shadow" value={shadowColor} onChange={setShadowColor} />
          </Collapsible>

          <Collapsible title="Nama Karakter" icon={Users} defaultOpen={false}>
            <p className="text-[11px] text-[#5b5e66] mb-2 -mt-1">Nama karakter digunakan untuk membuat teks "/low" lebih putih dibanding pemain lain.</p>
            <TextInput value={characterName} onChange={setCharacterName} placeholder="Jordan Baker" />
          </Collapsible>

          <Collapsible title="Nama File" icon={Type} defaultOpen={false}>
            <TextInput value={fileName} onChange={setFileName} placeholder="Robbery-Part1" />
          </Collapsible>

          <div className="h-4" />
        </aside>

        {/* PREVIEW */}
        <main className="flex-1 flex flex-col min-h-[420px] lg:min-h-0" style={{ background: isLight ? "#EAEBEF" : "#070809" }}>
          <div className="flex items-center justify-between px-5 py-3 border-b border-[#1A1C22] bg-[#0A0B0D]">
            <span className="text-[12px] font-semibold text-[#9AA0AC] uppercase tracking-wide">Preview</span>
            <div className="flex items-center gap-1.5">
              <button onClick={() => { setFitMode(false); setZoom((z) => Math.max(0.1, z - 0.1)); }} className="zoom-btn"><ZoomOut size={14} /></button>
              <span className="text-[11px] text-[#9AA0AC] font-mono w-12 text-center tabular-nums">{Math.round(effectiveZoom * 100)}%</span>
              <button onClick={() => { setFitMode(false); setZoom((z) => Math.min(3, z + 0.1)); }} className="zoom-btn"><ZoomIn size={14} /></button>
              <button onClick={() => setFitMode(true)} className="zoom-btn" title="Fit Screen"><Maximize2 size={13} /></button>
              <button onClick={resetZoom} className="zoom-btn" title="Reset Zoom"><RotateCcw size={13} /></button>
            </div>
          </div>

          <div ref={wrapperRef} className="flex-1 overflow-auto flex items-center justify-center p-6 gts-canvas-bg">
            <div
              style={{
                width: resW * effectiveZoom,
                height: resH * effectiveZoom,
                boxShadow: "0 20px 60px -20px rgba(0,0,0,0.8), 0 0 0 1px rgba(255,255,255,0.06)",
              }}
              className="rounded-md overflow-hidden shrink-0"
            >
              <canvas
                ref={canvasRef}
                style={{ width: resW * effectiveZoom, height: resH * effectiveZoom, display: "block" }}
              />
            </div>
          </div>

          {/* Export bar */}
          <div className="border-t border-[#1A1C22] bg-[#0A0B0D] px-5 py-4 flex flex-col sm:flex-row gap-3">
            <button
              onClick={copyToClipboard}
              className="flex-1 flex items-center justify-center gap-2 bg-[#3B6FE0] hover:bg-[#4a7af0] text-white font-semibold text-[13.5px] py-3 rounded-xl transition-colors shadow-lg shadow-[#3B6FE0]/15"
            >
              <Copy size={16} /> Copy Clipboard
            </button>
            <button
              onClick={() => exportImage("png")}
              className="flex-1 flex items-center justify-center gap-2 bg-[#15171c] hover:bg-[#1c1f26] border border-[#21242C] text-[#E8E9EB] font-semibold text-[13.5px] py-3 rounded-xl transition-colors"
            >
              <Download size={16} /> Download PNG
            </button>
            <button
              onClick={() => exportImage("jpg")}
              className="flex-1 flex items-center justify-center gap-2 bg-[#15171c] hover:bg-[#1c1f26] border border-[#21242C] text-[#E8E9EB] font-semibold text-[13.5px] py-3 rounded-xl transition-colors"
            >
              <Download size={16} /> Download JPG
            </button>
          </div>
        </main>
      </div>

      <ToastStack toasts={toasts} />
    </div>
  );
}

// ---------- Font + global styles ----------

function FontLoader() {
  useEffect(() => {
    const link = document.createElement("link");
    link.rel = "stylesheet";
    link.href = "https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=Anton&family=Bebas+Neue&family=Baloo+2:wght@500;600;700;800&family=Quicksand:wght@500;600;700&display=swap";
    document.head.appendChild(link);
    return () => { document.head.removeChild(link); };
  }, []);
  return null;
}

